import { CodeBlock as CodeBlockRoot, type CodeBlockProps } from "./code-block";
import { CodeBlockContent, type CodeBlockContentProps } from "./code-block-content";
import { CodeBlockHeader, type CodeBlockHeaderProps } from "./code-block-header";
import { CodeBlockLabel, type CodeBlockLabelProps } from "./code-block-label";
import { CodeBlockLine, type CodeBlockLineProps, type CodeBlockToken, type CodeBlockLineType } from "./code-block-line";

const CodeBlock = Object.assign(CodeBlockRoot, {
  Content: CodeBlockContent,
  Header: CodeBlockHeader,
  Label: CodeBlockLabel,
  Line: CodeBlockLine,
});

export {
  CodeBlock,
  CodeBlockContent,
  CodeBlockHeader,
  CodeBlockLabel,
  CodeBlockLine,
  type CodeBlockProps,
  type CodeBlockContentProps,
  type CodeBlockHeaderProps,
  type CodeBlockLabelProps,
  type CodeBlockLineProps,
  type CodeBlockToken,
  type CodeBlockLineType,
};

"use client";

import type { ComponentProps } from "react";
import { cn } from "@/lib/utils";

export interface CodeBlockProps extends ComponentProps<"div"> {
  language?: string;
  label?: string;
}

export function CodeBlock({ language, label, className, children, ref, ...props }: CodeBlockProps) {
  return (
    <div ref={ref} role="region" aria-roledescription="code block" aria-label={label ?? (language ? `${language} code` : "Code block")} data-language={language} className={cn("border border-border bg-background overflow-hidden rounded-sm", className)} {...props}>
      {children}
    </div>
  );
}

"use client";

import type { ComponentProps } from "react";
import { cn } from "@/lib/utils";
import { ScrollArea } from "../scroll-area/scroll-area";
import { CodeBlockLine } from "./code-block-line";

export interface CodeBlockContentProps extends ComponentProps<"div"> {
  showLineNumbers?: boolean;
}

export function CodeBlockContent({
  showLineNumbers = true,
  className,
  children,
  ref,
  "aria-label": ariaLabel,
  "aria-labelledby": ariaLabelledBy,
  ...props
}: CodeBlockContentProps) {
  return (
    <ScrollArea
      orientation="both"
      tabIndex={0}
      ref={ref}
      aria-label={ariaLabelledBy ? undefined : (ariaLabel ?? "Code content")}
      aria-labelledby={ariaLabelledBy}
      className={cn("focus-visible:outline focus-visible:outline-1 focus-visible:outline-border", className)}
      {...props}
    >
      <pre className="p-4 font-mono text-xs leading-relaxed">
        {typeof children === "string"
          ? children.split("\n").map((line, i) => (
              <CodeBlockLine key={i} number={showLineNumbers ? i + 1 : undefined} content={line} />
            ))
          : children}
      </pre>
    </ScrollArea>
  );
}

"use client";

import type { ComponentProps } from "react";
import { cn } from "@/lib/utils";

export type CodeBlockHeaderProps = ComponentProps<"div">;

export function CodeBlockHeader({ className, ref, ...props }: CodeBlockHeaderProps) {
  return <div ref={ref} className={cn("flex items-center justify-between px-4 py-2 border-b border-border bg-border/10", className)} {...props} />;
}

"use client";

import type { ComponentProps } from "react";
import { cn } from "@/lib/utils";

export type CodeBlockLabelProps = ComponentProps<"span">;

export function CodeBlockLabel({ className, children, ref, ...props }: CodeBlockLabelProps) {
  return (
    <span ref={ref} className={cn("text-xs text-foreground/60 font-bold uppercase tracking-wider", className)} {...props}>
      {children}
    </span>
  );
}

"use client";

import type { ComponentProps } from "react";
import { cn } from "@/lib/utils";

/** @see @diffgazer/registry docs-data CodeBlockToken (base without `className`) */
export interface CodeBlockToken {
  text: string;
  color?: string;
  className?: string;
}

export type CodeBlockLineType = "highlight" | "added" | "removed";

export interface CodeBlockLineProps extends Omit<ComponentProps<"span">, "content"> {
  number?: number;
  content: string | CodeBlockToken[];
  type?: CodeBlockLineType;
}

export function CodeBlockLine({ number, content, type, className, ref, ...props }: CodeBlockLineProps) {
  return (
    <span ref={ref} className={cn("flex", type === "highlight" && "bg-muted/50", className)} {...props}>
      {number != null && (
        <span aria-hidden="true" className="w-8 text-muted-foreground border-r border-border mr-2 text-right pr-1 select-none shrink-0">
          {number}
        </span>
      )}
      {(type === "added" || type === "removed") && (
        <span className="sr-only">{type === "added" ? "Added: " : "Removed: "}</span>
      )}
      <code className={cn("whitespace-pre", type === "added" && "text-success", type === "removed" && "text-destructive")}>
        {typeof content === "string"
          ? content
          : content.map((token, i) => (
              <span key={i} style={{ color: token.color }} className={token.className}>
                {token.text}
              </span>
            ))}
      </code>
    </span>
  );
}
